# ============================================================
# CELL 6: Audio Loading — load, resample, normalize, pad/trim
# ============================================================
def load_audio(file_path: str, config: dict) -> torch.Tensor:
    """
    Load a .wav file and return a fixed-length, mono, normalized waveform.

    Steps:
      1. Load with torchaudio (handles most formats)
      2. Convert to mono by averaging channels
      3. Resample to CONFIG['sample_rate']
      4. Trim or pad to CONFIG['num_samples']
      5. Peak-normalize to [-1, 1]

    Returns:
      waveform : Tensor of shape (1, num_samples)
    """
    try:
        import librosa
        import numpy as np
        # 1. Load with librosa (handles most formats, robust fallback)
        # 2. Convert to mono natively
        # 3. Resample to CONFIG['sample_rate'] natively
        y, sr = librosa.load(file_path, sr=config["sample_rate"], mono=True)
        waveform = torch.from_numpy(y).unsqueeze(0)
    except Exception as e:
        raise RuntimeError(f"Failed to load {file_path}: {e}")

    # Step 4 — trim / pad
    target = config["num_samples"]
    length = waveform.shape[1]
    if length > target:
        waveform = waveform[:, :target]
    elif length < target:
        pad_size = target - length
        waveform = torch.nn.functional.pad(waveform, (0, pad_size))

    # Step 5 — peak normalize
    peak = waveform.abs().max()
    if peak > 0:
        waveform = waveform / peak

    return waveform   # shape: (1, num_samples)


print("✅ Audio loading utility defined.")

# ============================================================
# CELL 7: Data Augmentation (raw waveform only)
# ============================================================
def add_noise(waveform: torch.Tensor, noise_level: float = 0.005) -> torch.Tensor:
    """Add Gaussian white noise."""
    noise = torch.randn_like(waveform) * noise_level
    return (waveform + noise).clamp(-1.0, 1.0)


def time_shift(waveform: torch.Tensor, max_shift_ratio: float = 0.1) -> torch.Tensor:
    """Randomly shift waveform left or right (circular roll)."""
    shift = int(random.uniform(-max_shift_ratio, max_shift_ratio) * waveform.shape[1])
    return torch.roll(waveform, shifts=shift, dims=1)


def time_stretch(waveform: torch.Tensor, rate_range: tuple = (0.9, 1.1)) -> torch.Tensor:
    """
    Approximate time-stretch by resampling at a slightly different rate
    then trimming/padding back to the original length.
    Avoids spectrogram computation — keeps everything in raw waveform domain.
    """
    rate        = random.uniform(*rate_range)
    orig_len    = waveform.shape[1]
    new_len     = int(orig_len * rate)

    # Interpolate (1D linear) to new_len
    wav_np      = waveform.numpy()                          # (1, orig_len)
    x_old       = np.linspace(0, 1, orig_len)
    x_new       = np.linspace(0, 1, new_len)
    stretched   = np.interp(x_new, x_old, wav_np[0])       # (new_len,)
    stretched   = torch.tensor(stretched, dtype=torch.float32).unsqueeze(0)  # (1, new_len)

    # Re-trim or pad to original length
    if new_len > orig_len:
        stretched = stretched[:, :orig_len]
    else:
        pad_size  = orig_len - new_len
        stretched = torch.nn.functional.pad(stretched, (0, pad_size))

    return stretched


def augment(waveform: torch.Tensor, apply_prob: float = 0.5) -> torch.Tensor:
    """Apply each augmentation independently with probability `apply_prob`."""
    if random.random() < apply_prob:
        waveform = add_noise(waveform)
    if random.random() < apply_prob:
        waveform = time_shift(waveform)
    if random.random() < apply_prob:
        waveform = time_stretch(waveform)
    return waveform


print("✅ Augmentation utilities defined.")

