# CELL 8: Custom Dataset Class (FINAL FIXED VERSION)
# ============================================================
class RespiScopeDataset(Dataset):
    def __init__(self, root_folders, config, augment_data=False):
        self.config = config
        self.augment_data = augment_data
        self.samples = []   # (file_path, type_label, condition_label)

        self._scan_folders(root_folders)

        print(f"✅ Total samples loaded: {len(self.samples)}")
        print("🔍 Sample entries:", self.samples[:5])

    def _scan_folders(self, root_folders):
        for root in root_folders:
            if not os.path.isdir(root):
                print(f"⚠️ Skipping missing folder: {root}")
                continue

            root_lower = root.lower()

            for class_dir in sorted(os.listdir(root)):
                class_path = os.path.join(root, class_dir)

                if not os.path.isdir(class_path):
                    continue

                folder_name = class_dir.lower()

                # =========================
                # 🔥 LABEL MAPPING LOGIC
                # =========================
                if "lung-sound" in root_lower:
                    type_lbl = 1
                    if folder_name == "healthy":
                        cond_lbl = 0
                    elif folder_name == "asthma":
                        cond_lbl = 1
                    elif folder_name == "pneumonia":
                        cond_lbl = 2
                    else:
                        print(f"⚠️ Unknown lung class '{folder_name}' — skipping.")
                        continue

                elif "heart-sound" in root_lower:
                    type_lbl = 0
                    if folder_name == "normal":
                        cond_lbl = 0
                    elif folder_name == "abnormal":
                        cond_lbl = 3
                    else:
                        print(f"⚠️ Unknown heart class '{folder_name}' — skipping.")
                        continue

                else:
                    print(f"⚠️ Unknown root folder '{root}' — skipping.")
                    continue

                # =========================
                # Collect WAV files
                # =========================
                wav_files = [
                    os.path.join(class_path, f)
                    for f in os.listdir(class_path)
                    if f.lower().endswith(".wav")
                ]

                if len(wav_files) == 0:
                    print(f"⚠️ No .wav files in {class_path}")

                for wav in wav_files:
                    self.samples.append((wav, type_lbl, cond_lbl))

        if len(self.samples) == 0:
            raise RuntimeError("❌ No .wav files found! Check dataset path.")

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        file_path, type_lbl, cond_lbl = self.samples[idx]

        waveform = load_audio(file_path, self.config)  # (1, num_samples)

        if self.augment_data:
            waveform = augment(waveform)

        return (
            waveform,
            torch.tensor(type_lbl, dtype=torch.long),
            torch.tensor(cond_lbl, dtype=torch.long),
        )

print("✅ RespiScopeDataset class ready.")

