# ============================================================
# CELL 11: Temporal Convolutional Network (TCN)
# ============================================================

# ── Residual Block ────────────────────────────────────────────
class TCNResidualBlock(nn.Module):
    """
    One TCN residual block:
      Conv1d (dilated) → BatchNorm → ReLU → Dropout
      Conv1d (dilated) → BatchNorm → ReLU → Dropout
      + residual (1×1 conv if channel mismatch)
    """
    def __init__(self, in_channels, out_channels, kernel_size, dilation, dropout):
        super().__init__()
        # Same-padding for causal / symmetric convolution
        padding = (kernel_size - 1) * dilation // 2

        self.conv1 = nn.Conv1d(
            in_channels, out_channels,
            kernel_size=kernel_size,
            dilation=dilation,
            padding=padding,
        )
        self.bn1      = nn.BatchNorm1d(out_channels)
        self.relu1    = nn.ReLU()
        self.drop1    = nn.Dropout(dropout)

        self.conv2 = nn.Conv1d(
            out_channels, out_channels,
            kernel_size=kernel_size,
            dilation=dilation,
            padding=padding,
        )
        self.bn2      = nn.BatchNorm1d(out_channels)
        self.relu2    = nn.ReLU()
        self.drop2    = nn.Dropout(dropout)

        # 1×1 projection for residual if channels differ
        self.residual_conv = (
            nn.Conv1d(in_channels, out_channels, kernel_size=1)
            if in_channels != out_channels else nn.Identity()
        )

    def forward(self, x):
        residual = self.residual_conv(x)

        out = self.drop1(self.relu1(self.bn1(self.conv1(x))))
        out = self.drop2(self.relu2(self.bn2(self.conv2(out))))

        # Trim if temporal dimension drifted (safety guard)
        if out.shape[-1] != residual.shape[-1]:
            min_len = min(out.shape[-1], residual.shape[-1])
            out      = out[..., :min_len]
            residual = residual[..., :min_len]

        return out + residual


# ── Full TCN backbone ─────────────────────────────────────────
class TCNBackbone(nn.Module):
    """
    Stack of TCNResidualBlocks with exponentially growing dilation.
    Input  : (B, 1, T)
    Output : (B, channels[-1], T')
    """
    def __init__(self, channels, kernel_size, dropout):
        super().__init__()
        layers = []
        in_ch  = 1
        for i, out_ch in enumerate(channels):
            dilation = 2 ** i        # 1, 2, 4, 8, …
            layers.append(
                TCNResidualBlock(in_ch, out_ch, kernel_size, dilation, dropout)
            )
            in_ch = out_ch
        self.network = nn.Sequential(*layers)

    def forward(self, x):
        return self.network(x)       # (B, channels[-1], T')


# ── Full RespiScope model ─────────────────────────────────────
class RespiScopeModel(nn.Module):
    """
    TCN backbone → Global Average Pooling →
      Head 1 : sound type  (Heart / Lung)
      Head 2 : condition   (Normal / Asthma / Pneumonia / HeartAbnormal)
    """
    def __init__(self, config):
        super().__init__()
        channels    = config["tcn_channels"]
        kernel_size = config["kernel_size"]
        dropout     = config["dropout"]

        self.backbone = TCNBackbone(channels, kernel_size, dropout)

        feat_dim = channels[-1]
        self.pool = nn.AdaptiveAvgPool1d(1)   # (B, feat_dim, 1)

        # Head 1 — sound type
        self.head_type = nn.Sequential(
            nn.Linear(feat_dim, 128),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(128, config["num_type_cls"]),
        )

        # Head 2 — condition
        self.head_cond = nn.Sequential(
            nn.Linear(feat_dim, 128),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(128, config["num_cond_cls"]),
        )

    def forward(self, x):
        # x : (B, 1, T)
        features   = self.backbone(x)          # (B, C, T')
        pooled     = self.pool(features)        # (B, C, 1)
        pooled     = pooled.squeeze(-1)         # (B, C)

        out_type   = self.head_type(pooled)     # (B, num_type_cls)
        out_cond   = self.head_cond(pooled)     # (B, num_cond_cls)

        return out_type, out_cond


